import React from 'react';
import TabPage from '../../components/common/TabPage';
import { FiShield, FiUsers, FiBriefcase, FiDollarSign, FiClock, FiBookmark } from 'react-icons/fi';
import AdminUsers from './AdminUsers';
import AdminJobTitles from './AdminJobTitles';
import AdminPayGrades from './AdminPayGrades';
import AdminWorkShifts from './AdminWorkShifts';
import AdminOrganization from './AdminOrganization';

const tabs = [
  { key: 'users', label: 'Users', icon: FiUsers, component: AdminUsers },
  { key: 'job-titles', label: 'Job Titles', icon: FiBriefcase, component: AdminJobTitles },
  { key: 'pay-grades', label: 'Pay Grades', icon: FiDollarSign, component: AdminPayGrades },
  { key: 'work-shifts', label: 'Work Shifts', icon: FiClock, component: AdminWorkShifts },
  { key: 'organization', label: 'Organization', icon: FiBookmark, component: AdminOrganization },
];

const AdminPage = () => <TabPage tabs={tabs} defaultTab="users" moduleIcon={FiShield} moduleTitle="Admin" />;

export default AdminPage;
